proof:
-- By definition of `ComplexMeasure.rnDeriv`, we have that `μ.rnDeriv μ.var = 0` iff `μ = 0`.
ext x; simp [ang];
unfold ComplexMeasure.rnDeriv;
congr <;> simp +decide [ SignedMeasure.rnDeriv ];
· rw [ show ( VectorMeasure.mapRange ( -μ ) Complex.reLm.toAddMonoidHom Complex.continuous_re ) = - ( VectorMeasure.mapRange μ Complex.reLm.toAddMonoidHom Complex.continuous_re ) by ext; simp +decide ];
  rw [ MeasureTheory.SignedMeasure.toJordanDecomposition_neg ];
  rw [ MeasureTheory.JordanDecomposition.neg_posPart, MeasureTheory.JordanDecomposition.neg_negPart ];
· rw [ show ( VectorMeasure.mapRange ( -μ ) Complex.imLm.toAddMonoidHom Complex.continuous_im ) = - ( VectorMeasure.mapRange μ Complex.imLm.toAddMonoidHom Complex.continuous_im ) by ext; simp +decide ];
  rw [ MeasureTheory.SignedMeasure.toJordanDecomposition_neg ];
  rw [ MeasureTheory.JordanDecomposition.neg_posPart, MeasureTheory.JordanDecomposition.neg_negPart ]

